class I18nService {
  public currentLanguage: LanguageType = 'zh';
  private listeners = new Set<() => void>();
  
  constructor() {
    // Default to Chinese
    this.currentLanguage = 'zh';
  }
  
  // Initialize language settings
  async initialize(): Promise<void> {
    try {
      const config = configService.getConfig();

      // Check if language settings have already been initialized
      const languageInitialized = config.language_initialized;

      const validLanguages: LanguageType[] = ['zh', 'en', 'zh-TW', 'ko', 'ja', 'ru', 'fr', 'de', 'vi'];
      if (languageInitialized !== true) {
        // Possibly first launch or legacy user upgrade
        // To protect legacy users' language settings, check for non-default language config
        const hasCustomLanguage = config.language && config.language !== 'zh';

        if (hasCustomLanguage) {
          // Legacy user has manually set language (non-default), preserve their setting
          console.log(`[i18n] Legacy user detected with custom language: ${config.language}`);
          this.currentLanguage = config.language as LanguageType;
          configService.updateConfig({
            ...config,
            language_initialized: true
          });
        } else {
          // New user or legacy user with default Chinese: detect system language
          try {
            const systemLocale = await window.electron.appInfo.getSystemLocale();
            const defaultLanguage = this.inferLanguageFromLocale(systemLocale);

            console.log(`[i18n] First run detected. System locale: ${systemLocale}, default language: ${defaultLanguage}`);

            this.currentLanguage = defaultLanguage;

            // Save language config and initialization flag
            configService.updateConfig({
              ...config,
              language: defaultLanguage,
              language_initialized: true
            });
          } catch (error) {
            console.error('Failed to get system locale:', error);
            // If getting system language fails, default to English
            this.currentLanguage = 'en';
            configService.updateConfig({
              ...config,
              language: 'en',
              language_initialized: true
            });
          }
        }
      } else {
        // Not first launch: use saved language config
        if (config.language && validLanguages.includes(config.language as LanguageType)) {
          this.currentLanguage = config.language as LanguageType;
        } else {
          // If config is invalid, fallback to English
          this.currentLanguage = 'en';
          configService.updateConfig({
            ...config,
            language: 'en'
          });
        }
      }
    } catch (error) {
      console.error('Failed to initialize language:', error);
      // Default to English
      this.currentLanguage = 'en';
    }
  }

  // Infer application language from system language
  private inferLanguageFromLocale(systemLocale: string): LanguageType {
    const lower = systemLocale.toLowerCase();
    if (lower === 'zh-cn' || lower === 'zh_cn') return 'zh';
    if (lower.startsWith('zh-tw') || lower.startsWith('zh-hk') || lower.startsWith('zh_tw') || lower.startsWith('zh_hk')) return 'zh-TW';
    if (lower.startsWith('ko')) return 'ko';
    if (lower.startsWith('ja')) return 'ja';
    if (lower.startsWith('ru')) return 'ru';
    if (lower.startsWith('fr')) return 'fr';
    if (lower.startsWith('de')) return 'de';
    return 'en';
  }
  
  // Set language
  setLanguage(language: LanguageType, options: { persist?: boolean } = {}): void {
    const { persist = true } = options;
    const hasChanged = this.currentLanguage !== language;
    this.currentLanguage = language;

    if (hasChanged) {
      this.listeners.forEach((listener) => listener());
    }

    if (!persist) {
      return;
    }

    // Update config
    try {
      const config = configService.getConfig();
      configService.updateConfig({
        ...config,
        language
      });
    } catch (error) {
      console.error('Failed to save language setting:', error);
    }
  }
  
  // Get current language
  getLanguage(): LanguageType {
    return this.currentLanguage;
  }

  // Get date formatting locale (for toLocaleString / toLocaleDateString)
  getDateLocale(): string {
    const map: Record<LanguageType, string> = {
      zh: 'zh-CN', en: 'en-US', 'zh-TW': 'zh-TW',
      ko: 'ko-KR', ja: 'ja-JP', ru: 'ru-RU', fr: 'fr-FR', de: 'de-DE', vi: 'vi-VN',
    };
    return map[this.currentLanguage] || 'en-US';
  }
  
  // Get translated text (prefer current language, fall back to English, then Chinese)
  t(key: string, params?: Record<string, string>): string {
    let text = translations[this.currentLanguage]?.[key];
    if (text === undefined || text === null) text = translations['en']?.[key];
    if (text === undefined || text === null) text = translations['zh']?.[key];
    if (text === undefined || text === null) return key;
    if (params) {
      for (const [k, v] of Object.entries(params)) {
        text = text.replace(new RegExp(`\\{${k}\\}`, 'g'), v);
      }
    }
    return text;
  }

  subscribe(listener: () => void): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }
}

export const i18nService = new I18nService(); 
